const raw = $json.content?.parts?.[0]?.text || $json.text || "";

const cleaned = raw
  .replace(/```json\s*/i, "")
  .replace(/```\s*$/i, "")
  .trim();

let obj;
try {
  obj = JSON.parse(cleaned);
} catch (e) {
  throw new Error("Gemini output not valid JSON after cleaning. Raw output: " + raw);
}

return [obj];
